            cv("d_mch", 25, lambda: "–®–∞–љ—Б –Љ–µ–і–Є–∞ (%)", validator=vi),
            cv("d_mych", 100, lambda: "–®–∞–љ—Б —А–µ–њ–ї–∞—П (%)", validator=vi),
